const CUSTOMER_TIERS={DONG:{id:"dong",name:"Thành viên Đồng",icon:"🥉",minPoints:0,maxPoints:4999,benefits:["Tích 10đ = 1 point","Quà sinh nhật 50 points"],color:"#CD7F32"},BAC:{id:"bac",name:"Thành viên Bạc",icon:"🥈",minPoints:5e3,maxPoints:14999,benefits:["Tích 8đ = 1 point","Quà sinh nhật 100 points","Ưu tiên đặt bàn"],color:"#C0C0C0"},VANG:{id:"vang",name:"Thành viên Vàng",icon:"🥇",minPoints:15e3,maxPoints:49999,benefits:["Tích 6đ = 1 point","Quà sinh nhật 200 points","Free ship 5km","Menu riêng"],color:"#FFD700"},KIM_CUONG:{id:"kim-cuong",name:"Thành viên Kim Cương",icon:"💎",minPoints:5e4,maxPoints:1/0,benefits:["Tích 5đ = 1 point","Quà sinh nhật 500 points","Free ship toàn quốc","Event đặc biệt"],color:"#B9F2FF"}},POINTS_RULES={BASE_EARN_RATE:10,REDEMPTION_RATE:100,BIRTHDAY_BONUS:{dong:50,bac:100,vang:200,"kim-cuong":500},SPECIAL_EVENTS:{"2/9":2,"30/4":2,tet:3,"black-friday":5}};class LoyaltyManager{constructor(){this.customerId=this._getCustomerId(),this.customer=this._loadCustomer(),this.transactionHistory=this._loadHistory()}_getCustomerId(){let t=localStorage.getItem("fnb_customer_id");return t||(t="CUST"+Date.now()+Math.random().toString(36).substr(2,4).toUpperCase(),localStorage.setItem("fnb_customer_id",t)),t}_loadCustomer(){const t=localStorage.getItem("fnb_loyalty_customer");return t?JSON.parse(t):{id:this.customerId,name:"",phone:"",email:"",points:0,lifetimePoints:0,tier:"dong",joinedDate:(new Date).toISOString(),lastActivity:(new Date).toISOString(),birthday:null}}_saveCustomer(){localStorage.setItem("fnb_loyalty_customer",JSON.stringify(this.customer))}_loadHistory(){const t=localStorage.getItem("fnb_loyalty_history");return t?JSON.parse(t):[]}_saveHistory(){localStorage.setItem("fnb_loyalty_history",JSON.stringify(this.transactionHistory))}getTier(){const t=Object.values(CUSTOMER_TIERS);for(const n of t)if(this.customer.points>=n.minPoints&&this.customer.points<=n.maxPoints)return n;return CUSTOMER_TIERS.DONG}getNextTierProgress(){const t=this.getTier(),n=Object.values(CUSTOMER_TIERS),e=n.findIndex(n=>n.id===t.id)+1;if(e>=n.length)return{progress:100,nextTier:null,pointsNeeded:0};const i=n[e],s=i.minPoints-this.customer.points,r=(this.customer.points-t.minPoints)/(t.maxPoints-t.minPoints)*100;return{progress:Math.min(100,r),nextTier:i,pointsNeeded:s}}async earnPoints(t,n=null){const e=this.getTier();let i=POINTS_RULES.BASE_EARN_RATE;switch(e.id){case"bac":i=8;break;case"vang":i=6;break;case"kim-cuong":i=5}const s=new Date,r=`${s.getDate()}/${s.getMonth()+1}`;POINTS_RULES.SPECIAL_EVENTS[r]&&(i/=POINTS_RULES.SPECIAL_EVENTS[r]);const o=Math.floor(t/1e3/i*10);this.customer.points+=o,this.customer.lifetimePoints+=o,this.customer.lastActivity=(new Date).toISOString();const a=this.getTier(),c=a.id!==e.id,d={id:"TXN"+Date.now(),type:"earn",points:o,orderTotal:t,orderId:n,date:(new Date).toISOString(),description:`Tích điểm từ đơn hàng ${n||"#"+Math.random().toString(36).substr(2,6)}`,tierAfter:a.id};return this.transactionHistory.unshift(d),this._saveCustomer(),this._saveHistory(),c&&this._triggerTierUpgrade(a),{pointsEarned:o,newBalance:this.customer.points,tier:a,tierUpgraded:c}}redeemPoints(t,n=null){if(t>this.customer.points)throw new Error("Không đủ điểm để đổi");if(t<100)throw new Error("Tối thiểu 100 points để đổi");const e=t/POINTS_RULES.REDEMPTION_RATE*1e4;this.customer.points-=t,this.customer.lastActivity=(new Date).toISOString();const i={id:"TXN"+Date.now(),type:"redeem",points:-t,discountValue:e,orderId:n,date:(new Date).toISOString(),description:`Đổi ${t} points thành ${e.toLocaleString("vi-VN")}đ`,tierAfter:this.getTier().id};return this.transactionHistory.unshift(i),this._saveCustomer(),this._saveHistory(),{pointsRedeemed:t,discountValue:e,newBalance:this.customer.points}}giveBirthdayBonus(){const t=this.getTier(),n=POINTS_RULES.BIRTHDAY_BONUS[t.id]||50;this.customer.points+=n,this.customer.lifetimePoints+=n;const e={id:"TXN"+Date.now(),type:"bonus",points:n,date:(new Date).toISOString(),description:"🎂 Quà sinh nhật",tierAfter:this.getTier().id};return this.transactionHistory.unshift(e),this._saveCustomer(),this._saveHistory(),n}getHistory(t=20){return this.transactionHistory.slice(0,t)}updateCustomerInfo(t){this.customer={...this.customer,...t},this._saveCustomer()}isBirthdayToday(){if(!this.customer.birthday)return!1;const t=new Date,n=new Date(this.customer.birthday);return t.getDate()===n.getDate()&&t.getMonth()===n.getMonth()}_triggerTierUpgrade(t){const n=new CustomEvent("loyalty-tier-upgrade",{detail:{customerId:this.customerId,newTier:t,message:`🎉 Chúc mừng! Bạn đã nâng hạng lên ${t.icon} ${t.name}!`}});window.dispatchEvent(n)}resetYearly(){}}function renderTierBadge(t){return`\n        <div class="tier-badge" style="background: linear-gradient(135deg, ${t.color}, ${t.color}88);">\n            <span class="tier-icon">${t.icon}</span>\n            <span class="tier-name">${t.name}</span>\n        </div>\n    `}function renderPointsBalance(t){return`\n        <div class="points-balance">\n            <span class="points-value">${t.toLocaleString("vi-VN")}</span>\n            <span class="points-label">points</span>\n        </div>\n    `}function renderTierProgress(t,n){return n?`\n        <div class="tier-progress">\n            <div class="tier-progress-header">\n                <span>${Math.round(t)}% đến ${n.icon} ${n.name}</span>\n            </div>\n            <div class="tier-progress-bar">\n                <div class="tier-progress-fill" style="width: ${Math.min(100,t)}%"></div>\n            </div>\n        </div>\n    `:'<div class="tier-max">🏆 Max Tier Achieved!</div>'}function renderTransactionItem(t){return`\n        <div class="transaction-item">\n            <div class="transaction-icon" style="color: ${{earn:"#10b981",redeem:"#ef4444",bonus:"#f59e0b"}[t.type]}">\n                ${{earn:"➕",redeem:"🔻",bonus:"🎁"}[t.type]}\n            </div>\n            <div class="transaction-info">\n                <span class="transaction-description">${t.description}</span>\n                <span class="transaction-date">${new Date(t.date).toLocaleDateString("vi-VN")}</span>\n            </div>\n            <span class="transaction-points ${t.points>0?"positive":"negative"}">\n                ${t.points>0?"+":""}${t.points}\n            </span>\n        </div>\n    `}window.LoyaltyManager=LoyaltyManager,window.CUSTOMER_TIERS=CUSTOMER_TIERS,window.POINTS_RULES=POINTS_RULES,window.renderTierBadge=renderTierBadge,window.renderPointsBalance=renderPointsBalance,window.renderTierProgress=renderTierProgress,window.renderTransactionItem=renderTransactionItem;